// ViewController.swift
import UIKit
import GoogleMaps
import Stripe

class ViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Set up Google Map view covering entire screen
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 10)
        let mapView = GMSMapView.map(withFrame: self.view.bounds, camera: camera)
        mapView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        self.view.addSubview(mapView)
        
        // Add a Stripe Payment button
        let paymentButton = UIButton(type: .system)
        paymentButton.setTitle("Pay with Stripe", for: .normal)
        paymentButton.backgroundColor = UIColor.systemBlue
        paymentButton.setTitleColor(.white, for: .normal)
        paymentButton.layer.cornerRadius = 5
        paymentButton.translatesAutoresizingMaskIntoConstraints = false
        paymentButton.addTarget(self, action: #selector(payButtonTapped), for: .touchUpInside)
        self.view.addSubview(paymentButton)
        
        // Button constraints
        NSLayoutConstraint.activate([
            paymentButton.bottomAnchor.constraint(equalTo: self.view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
            paymentButton.centerXAnchor.constraint(equalTo: self.view.centerXAnchor),
            paymentButton.widthAnchor.constraint(equalToConstant: 200),
            paymentButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    @objc func payButtonTapped() {
        // For demo purposes, simulate a payment process.
        let alert = UIAlertController(title: "Stripe Payment", message: "Payment processed successfully!", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default, handler: nil))
        present(alert, animated: true, completion: nil)
    }
}